<script setup lang="ts">
import { useI18n } from "vue-i18n"
import { NAME_RULE } from "@/constants"
import { goPage } from "@/modules/utils/util"
import { ref, onMounted } from "vue"
import { storeToRefs } from "pinia"
import useStore from "@/stores"

const { t } = useI18n()

const store = useStore()

const { name } = storeToRefs(store.signup)
const nameInput = ref<HTMLInputElement | null>(null)
const nameError = ref("")

const validateName = () => {
  nameError.value = ""
  const nameRegex = /^(?:\p{L}|\p{L}\.|\p{L}(?:[\p{L}\p{M}\-'. ]*\p{L}))$/u

  if (!name.value) {
    nameError.value = "auth.error.name.required"
    return
  }

  if (!nameRegex.test(name.value)) {
    nameError.value = "auth.error.name.invalid"
  }
  
}

const clearName = () => {
  name.value = ""
}

const clearNameError = () => {
  nameError.value = ""
}

const goNextStep = () => {
  validateName()

  if (!nameError.value) {
    store.signup.setName(name.value)
    goPage("SignUpEmail")
  }
}

onMounted(() => {
  nameInput.value?.focus()
})
</script>

